const pieza = $('Webhook Prep').first().json.body.pieza;
const brief = Buffer.from($json.content, 'base64').toString('utf8');

function parseField(content, fieldName) {
  const lines = content.split('\n');
  for (const line of lines) {
    if (line.includes('**' + fieldName + '**')) {
      const parts = line.split('|');
      if (parts.length >= 3) return (parts[2] || '').trim();
    }
  }
  return '';
}

function slugify(value) {
  return String(value || pieza)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '');
}

const titulo = parseField(brief, 'Titulo de trabajo');
const pilarNombre = parseField(brief, 'Pilar');
const angulo = parseField(brief, 'Angulo FG');
const tesis = parseField(brief, 'Tesis central');
const formato = parseField(brief, 'Formato principal');
const plataformas = parseField(brief, 'Plataforma(s)');
const duracion = parseField(brief, 'Duracion / Extension');
const derivados = parseField(brief, 'Formatos derivados');
const serieEpisodio = parseField(brief, 'Serie / episodio');

const pilarMap = {
  'geopolitik drop': 'GD', 'bass & borders': 'BB',
  'frecuencia global': 'FG', 'blueprint': 'BP', 'behind the policy': 'BP'
};
const pilarCode = pilarMap[(pilarNombre || '').toLowerCase()] || 'FG';
const formatoNormalizado = (formato || '').toLowerCase();
const isPodcast = pieza.startsWith('EP_') || formatoNormalizado.includes('podcast');
const siteUrl = $vars.FG_SITE_URL || 'https://frecuenciaglobal.vercel.app';
const podcastFeedUrl = $vars.FG_PODCAST_RSS_URL || 'https://media.rss.com/frecuencia-global-podcast/feed.xml';
const podcastShowUrl = $vars.FG_PODCAST_SHOW_URL || 'https://rss.com/podcasts/frecuencia-global-podcast';
const slug = isPodcast ? slugify(titulo || pieza) : pieza.toLowerCase();

return [{ json: { pieza, titulo, pilarNombre, pilarCode, angulo, tesis, formato, plataformas, duracion, derivados, serieEpisodio, isPodcast, pieceType: isPodcast ? 'podcast' : 'editorial', slug, siteUrl, podcastFeedUrl, podcastShowUrl, videoMode: isPodcast ? 'editorial-visualizer' : 'standard' } }];

const d = $input.first().json;
const { pieza, titulo, pilarCode, angulo, tesis, isPodcast, slug, siteUrl, podcastFeedUrl, podcastShowUrl, duracion, serieEpisodio } = d;

const hashtagSets = {
  GD: ['#GeopolitikDrop', '#Geopolitica', '#RelacionesInternacionales', '#FrecuenciaGlobal'],
  BB: ['#BassAndBorders', '#CulturaGlobal', '#MusicaYGeopolitica', '#FrecuenciaGlobal'],
  FG: ['#FrecuenciaGlobal', '#AnalisisInternacional', '#Geopolitica', '#PoliticaGlobal'],
  BP: ['#BehindThePolicy', '#AnalisisPolitico', '#PoliticaInternacional', '#FrecuenciaGlobal']
};

const tags = hashtagSets[pilarCode] || hashtagSets.FG;
const tagsFull = tags.join(' ');
const tagsShort = tags.slice(0, 3).join(' ');
const desc = (tesis && tesis !== '[pendiente de desarrollo]') ? tesis : (angulo || '');
const editorialUrl = siteUrl + (isPodcast ? '/podcast/' + slug : '/contenido/' + pieza.toLowerCase());
const primaryPodcastUrl = podcastShowUrl && !podcastShowUrl.includes('[pendiente') ? podcastShowUrl : editorialUrl;
const canonicalUrl = isPodcast ? primaryPodcastUrl : editorialUrl;

if (isPodcast) {
  const safeTitle = titulo || pieza;
  const podcastSummary = desc || 'Episodio semanal de Frecuencia Global en formato audio-first con videopodcast en YouTube.';
  const youtubeTitle = safeTitle.length > 90 ? safeTitle.substring(0, 87) + '...' : safeTitle;
  const chapterLines = ['00:00 Intro', '02:30 Contexto', '07:30 Desarrollo', '12:30 Implicaciones', '16:00 Cierre'];
  const clipList = ['Clip 1 - hook principal (0:30-1:00)', 'Clip 2 - tension o dato fuerte (7:30-8:15)', 'Clip 3 - cierre / CTA (15:45-16:20)'];
  const showNotes = [podcastSummary, '', '- Pilar: ' + d.pilarNombre, '- Serie / episodio: ' + (serieEpisodio || pieza), '- Duracion objetivo: ' + (duracion || '18-25 min'), '- Salida: RSS.com, YouTube largo y web editorial opcional'].join('\n');
  const youtubeDescription = [youtubeTitle, '', podcastSummary, '', 'Capitulos sugeridos:', ...chapterLines, '', 'Podcast en RSS.com: ' + podcastShowUrl, 'Feed RSS: ' + podcastFeedUrl, 'Web editorial: ' + editorialUrl, '', tagsFull].join('\n');
  let xCopy = 'Nuevo episodio: ' + safeTitle + '\n\n' + canonicalUrl + '\n\n' + tagsShort;
  if (xCopy.length > 280) xCopy = xCopy.substring(0, 277) + '...';
  const igTags = tags.concat(['#Podcast', '#Videopodcast', '#YouTube']).join(' ');
  const igCaption = safeTitle + '\n\n' + podcastSummary + '\n\nNuevo episodio en RSS.com, Spotify, Apple Podcasts y YouTube.\n\n' + igTags;
  const liCaption = safeTitle + '\n\n' + podcastSummary + '\n\nFrecuencia Global convierte el episodio semanal en audio hosteado en RSS.com y videopodcast largo para YouTube.\n\n' + tagsFull;
  const ttCaption = (safeTitle + ' podcast + videopodcast ' + tagsShort).substring(0, 300);
  return [{ json: Object.assign({}, d, { canonicalUrl, editorialUrl, primaryPodcastUrl, podcastSummary, showNotes, youtubeTitle, youtubeDescription, chapterLines, clipList, xCopy, igCaption, liCaption, ttCaption, tagsFull, tagsShort, xCharCount: xCopy.length, ttCharCount: ttCaption.length }) }];
}

let xCopy = (titulo || pieza) + '\n\n' + tagsShort;
if (xCopy.length > 280) {
  const maxTitle = 280 - tagsShort.length - 4;
  xCopy = (titulo || pieza).substring(0, maxTitle) + '...\n\n' + tagsShort;
}
xCopy = xCopy.substring(0, 280);
const igTags = tags.concat(['#AnalisisInternacional', '#ContenidoGeopolitico', '#InformacionGlobal']).join(' ');
const igCaption = (titulo || pieza) + (desc ? '\n\n' + desc : '') + '\n\nAnalisis por Frecuencia Global.\n\n' + igTags;
const liCaption = (titulo || pieza) + (desc ? '\n\n' + desc : '') + '\n\nEn Frecuencia Global analizamos el cruce entre geopolitica, cultura e informacion global.\n\n' + tagsFull;
const hookTT = (titulo || pieza).length > 200 ? (titulo || pieza).substring(0, 197) + '...' : (titulo || pieza);
const ttCaption = (hookTT + ' ' + tags.slice(0, 3).join(' ')).substring(0, 300);

return [{ json: Object.assign({}, d, { canonicalUrl, xCopy, igCaption, liCaption, ttCaption, tagsFull, tagsShort, xCharCount: xCopy.length, ttCharCount: ttCaption.length }) }];

const trackerRes = $input.first().json;
const briefData = $('Leer Brief').first().json;
const copyData = $('Generar Copy por Plataforma').first().json;

let tracker = {};
if (trackerRes.content) {
  try { tracker = JSON.parse(Buffer.from(trackerRes.content, 'base64').toString('utf8')); } catch(e) {}
}
const sha = trackerRes.sha || null;

const pieza = briefData.pieza;
const ahora = new Date().toISOString();
if (!tracker[pieza]) tracker[pieza] = { historial: [], publicaciones: [] };
tracker[pieza].historial = tracker[pieza].historial || [];
tracker[pieza].historial.push({ estado: 'PUBLISH_READY', timestamp: ahora });
tracker[pieza].estado_actual = 'PUBLISH_READY';
tracker[pieza].ultima_actualizacion = ahora;
tracker[pieza].tipo = briefData.isPodcast ? 'podcast' : 'editorial';
if (briefData.isPodcast) {
  tracker[pieza].salidas = ['rss', 'web', 'youtube'];
}

const base64Content = Buffer.from(JSON.stringify(tracker, null, 2)).toString('base64');
return [{ json: Object.assign({}, copyData, { pieceType: briefData.isPodcast ? 'podcast' : 'editorial', base64Content, ...(sha ? { sha } : {}) }) }];
